// Command protoc-gen-devedge-authz is a protoc/buf plugin that emits, for every
// service method carrying the (infoblox.authz.v1.rule) annotation, a compile-time
// []authz.MethodRule table — the codegen variant of the authz/authzpb reflection
// extractor.
//
// Use this when you want a generated rule file (e.g. a compile-time table, or to
// avoid reading descriptors at runtime); use authz/authzpb when you prefer
// reflection and no generated file. Both produce identical []authz.MethodRule.
//
// For each .proto with annotated methods it writes "<name>.authz.go" alongside
// the generated .pb.go, declaring one exported slice per service:
//
//	var <Service>AuthzRules = []authz.MethodRule{ ... }
//
// Wire it like: grpcauthz.WithRules(pkg.<Service>AuthzRules...).
package main

import (
	"fmt"
	"strconv"

	"google.golang.org/protobuf/compiler/protogen"
	"google.golang.org/protobuf/proto"
	"google.golang.org/protobuf/types/descriptorpb"
	"google.golang.org/protobuf/types/pluginpb"

	authzv1 "github.com/infobloxopen/apis/proto/infoblox/authz/v1"
)

const authzImport = protogen.GoImportPath("github.com/infobloxopen/devedge-sdk/authz")

type ruleLine struct {
	method   string
	verb     string
	resource string
	public   bool
}

func main() {
	protogen.Options{}.Run(func(gen *protogen.Plugin) error {
		gen.SupportedFeatures = uint64(pluginpb.CodeGeneratorResponse_FEATURE_PROTO3_OPTIONAL)
		for _, f := range gen.Files {
			if f.Generate {
				generateFile(gen, f)
			}
		}
		return nil
	})
}

func generateFile(gen *protogen.Plugin, f *protogen.File) {
	type svc struct {
		name  string
		rules []ruleLine
	}
	var services []svc
	for _, s := range f.Services {
		var rules []ruleLine
		for _, m := range s.Methods {
			opts, ok := m.Desc.Options().(*descriptorpb.MethodOptions)
			if !ok || opts == nil || !proto.HasExtension(opts, authzv1.E_Rule) {
				continue
			}
			r, _ := proto.GetExtension(opts, authzv1.E_Rule).(*authzv1.Rule)
			if r == nil {
				continue
			}
			rules = append(rules, ruleLine{
				method:   fmt.Sprintf("/%s/%s", s.Desc.FullName(), m.Desc.Name()),
				verb:     r.GetVerb(),
				resource: r.GetResource(),
				public:   r.GetPublic(),
			})
		}
		if len(rules) > 0 {
			services = append(services, svc{name: s.GoName, rules: rules})
		}
	}
	if len(services) == 0 {
		return // nothing annotated in this file — emit nothing
	}

	g := gen.NewGeneratedFile(f.GeneratedFilenamePrefix+".authz.go", f.GoImportPath)
	methodRule := g.QualifiedGoIdent(authzImport.Ident("MethodRule"))
	verbType := g.QualifiedGoIdent(authzImport.Ident("Verb"))

	g.P("// Code generated by protoc-gen-devedge-authz. DO NOT EDIT.")
	g.P("// source: ", f.Desc.Path())
	g.P()
	g.P("package ", f.GoPackageName)
	g.P()
	for _, s := range services {
		g.P("// ", s.name, "AuthzRules are the authorization rules declared on ", s.name, "'s methods.")
		g.P("var ", s.name, "AuthzRules = []", methodRule, "{")
		for _, r := range s.rules {
			g.P("\t{")
			g.P("\t\tMethod: ", strconv.Quote(r.method), ",")
			if r.public {
				g.P("\t\tPublic: true,")
			} else {
				g.P("\t\tVerb: ", verbType, "(", strconv.Quote(r.verb), "),")
				if r.resource != "" {
					g.P("\t\tResource: ", strconv.Quote(r.resource), ",")
				}
			}
			g.P("\t},")
		}
		g.P("}")
		g.P()
	}
}
